const msg = $json.message.text || '';
const prompt = `Asagidaki kullanici mesajini siniflandir. SADECE su JSON semasiyla cevap ver: {"intent": "stok"|"emir"|"kur"|"sohbet", "arama": "..."}
- "stok": bir urunun stok adedini soruyor. "arama" alanina urun adi/kodunu yaz (or. "412", "vario").
- "emir": acik/planli uretim emirlerini soruyor. arama bos.
- "kur": doviz kuru soruyor (euro/dolar/TL). arama bos.
- "sohbet": digerleri. arama bos.
Mesaj: ${msg}`;
return [{ json: { prompt, mesaj: msg } }];

let intent = 'sohbet', arama = '';
try {
  const resp = JSON.parse($json.data);
  const c = resp.candidates[0].content.parts[0].text;
  const p = JSON.parse(c);
  if (['stok','emir','kur','sohbet'].includes(p.intent)) intent = p.intent;
  arama = (p.arama || '').toString().slice(0, 60);
} catch (e) { /* sohbete duser */ }
return [{ json: { intent, arama, mesaj: $('Intent Prompt').item.json.mesaj } }];

const esc = s => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const rows = $input.all().map(i => i.json).filter(r => r.name);
if (!rows.length) return [{ json: { cevap: esc(`"${$('Intent Coz').item.json.arama}" ile eslesen urun bulunamadi.`) } }];
const list = rows.map(r => `\u2022 ${esc(r.name)} [${esc(r.family)}]: ${r.qty} adet` + (r.critical > 0 && r.qty <= r.critical ? ' \u26a0' : '')).join('\n');
return [{ json: { cevap: '\ud83d\udce6 Stok durumu:\n' + list } }];

const esc = s => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const rows = $input.all().map(i => i.json).filter(r => r.product_name);
if (!rows.length) return [{ json: { cevap: 'Acik uretim emri yok.' } }];
const list = rows.map(r => `\u2022 #${r.id} ${esc(r.product_name)} \u00d7${r.qty} [${esc(r.status)}] (${r.tarih})`).join('\n');
return [{ json: { cevap: '\ud83c\udfed Acik emirler:\n' + list } }];

const r = $json.rates;
const eurtry = r.TRY;
const usdtry = r.TRY / r.USD;
return [{ json: { cevap: `\ud83d\udcb1 Kurlar (${$json.date}):\nEUR/TRY: ${eurtry.toFixed(2)}\nUSD/TRY: ${usdtry.toFixed(2)}` } }];

let cevap = 'Su an cevap uretemedim.';
try {
  const resp = JSON.parse($json.data);
  const c = resp.candidates;
  if (c && c[0] && c[0].content && c[0].content.parts && c[0].content.parts[0].text) cevap = c[0].content.parts[0].text;
} catch (e) { /* varsayilan mesaj kalir */ }
cevap = cevap.replace(/\*\*/g, '').replace(/^\s*[\*\-]\s+/gm, '\u2022 ').replace(/^#+\s*/gm, '');
cevap = cevap.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
if (cevap.length > 3500) cevap = cevap.slice(0, 3500) + '\u2026';
return [{ json: { cevap } }];
